func (a *adapter) CreateCharge(ctx context.Context, in creditpurchase.CreateChargeInput) (creditpurchase.Charge, error) {
	if err := in.Validate(); err != nil {
		return creditpurchase.Charge{}, err
	}
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *adapter) (creditpurchase.Charge, error) {
		create := tx.db.ChargeCreditPurchase.Create().SetNamespace(in.Namespace).SetCreditAmount(in.Intent.CreditAmount).SetSettlement(in.Intent.Settlement).SetStatusDetailed(creditpurchase.StatusCreated)
		create, err := chargemeta.Create(create, chargemeta.CreateInput{Namespace: in.Namespace, Intent: in.Intent.Intent, Status: meta.ChargeStatusCreated})
		if err != nil { return creditpurchase.Charge{}, err }
		dbCreditPurchase, err := create.Save(ctx)
		if err != nil { return creditpurchase.Charge{}, err }
		if err := tx.metaAdapter.RegisterCharges(ctx, meta.RegisterChargesInput{Namespace: in.Namespace, Type: meta.ChargeTypeCreditPurchase, Charges: []meta.IDWithUniqueReferenceID{{ID: dbCreditPurchase.ID, UniqueReferenceID: dbCreditPurchase.UniqueReferenceID}}}); err != nil { return creditpurchase.Charge{}, err }
		return MapCreditPurchaseChargeFromDB(dbCreditPurchase, meta.ExpandNone)
	})
}

func (e *Engine) BuildStandardInvoiceLines(ctx context.Context, input billing.BuildStandardInvoiceLinesInput) (billing.StandardLines, error) {
	stdLines, err := slicesx.MapWithErr(input.GatheringLines, func(gl billing.GatheringLine) (*billing.StandardLine, error) {
		return gl.AsNewStandardLine(input.Invoice.ID)
	})
	if err != nil { return nil, err }
	return e.CalculateLines(billing.CalculateLinesInput{Invoice: input.Invoice, Lines: stdLines})
}

func (s *service) Create(ctx context.Context, input creditpurchase.CreateInput) (creditpurchase.ChargeWithGatheringLine, error) {
	input.Intent = input.Intent.Normalized()
	if err := input.Validate(); err != nil { return creditpurchase.ChargeWithGatheringLine{}, err }
	return transaction.Run(ctx, s.adapter, func(ctx context.Context) (creditpurchase.ChargeWithGatheringLine, error) {
		charge, err := s.adapter.CreateCharge(ctx, creditpurchase.CreateChargeInput(input))
		if err != nil { return creditpurchase.ChargeWithGatheringLine{}, err }
		switch charge.Intent.Settlement.Type() {
		case creditpurchase.SettlementTypePromotional:
			sm, err := NewPromotionalCreditPurchaseStateMachine(StateMachineConfig{Charge: charge, Adapter: s.adapter, Service: s})
			if err != nil { return creditpurchase.ChargeWithGatheringLine{}, err }
			advanced, err := sm.AdvanceUntilStateStable(ctx)
			if err != nil { return creditpurchase.ChargeWithGatheringLine{}, err }
			if advanced != nil { charge = *advanced }
		case creditpurchase.SettlementTypeExternal:
			charge, err = s.onExternalCreditPurchase(ctx, charge)
		}
		return creditpurchase.ChargeWithGatheringLine{Charge: charge}, nil
	})
}
